function kthLargestValue(matrix, k) {
  let m = matrix.length;
  let n = matrix[0].length;
  let prefixXOR = Array.from({ length: m + 1 }, () => Array(n + 1).fill(0));
  let pq = new PriorityQueue(k);

  for (let i = 1; i <= m; i++) {
    for (let j = 1; j <= n; j++) {
      prefixXOR[i][j] = matrix[i - 1][j - 1] ^ prefixXOR[i - 1][j] ^ prefixXOR[i][j - 1] ^ prefixXOR[i - 1][j - 1];
      pq.offer(prefixXOR[i][j]);
      if (pq.size() > k) {
        pq.poll();
      }
    }
  }
  return pq.peek();
}

class PriorityQueue {
  constructor(k) {
    this.queue = [];
    this.k = k;
  }

  offer(element) {
    this.queue.push(element);
    this.queue.sort((a, b) => a - b);
  }

  poll() {
    return this.queue.shift();
  }

  size() {
    return this.queue.length;
  }

  peek() {
    return this.queue[0];
  }
}
```


    1. Create a prefix XOR matrix to store the XOR of all coordinates (0 <= i <= a, 0 <= j <= b).
2. Use a min-heap (priority queue) to maintain the k largest values as we iterate through the prefix XOR matrix.
3. For each coordinate in the prefix XOR matrix, XOR the matrix value with the other matrix elements.
4. Push the XOR value onto the priority queue.
5. If the size of the priority queue is more than k, pop the smallest element.
6. After iterating through all coordinates, return the top element in the priority queue as the kth largest value.

